#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

const int N=505;
int son[N*N][5],C=1,cnt[N*N],len,ans,sum[N*N],fa[N*N];
bool vis[N*N][505];
string s[N],S;

int get(char c)
{
    if(c=='A') return 0;
    if(c=='C') return 1;
    if(c=='T') return 2;
    if(c=='G') return 3;
    if(c=='*') return 4;
    return 5;
}

void insert(string s)
{
    int len=s.length(),p=1;
    FOI(c,s)
    {
        int g=get(c);
        if(!son[p][g]) son[p][g]=++C;
        sum[p]++;
        fa[son[p][g]]=p;
        p=son[p][g];
    }
    sum[p]++;
    cnt[p]++;
}

void dfs(int p,int l)
{
    if(sum[p]==0) return;
    if(vis[p][l]) return;
    vis[p][l]=1;

    if(l==len)
    {
        ans+=cnt[p];
        int& c=cnt[p];
        int tp=p;
        while(tp!=0) sum[tp]-=c,tp=fa[tp];
        c=0;
        return;
    }

    int g=get(S[l]);
    if(g<4)
    {
        if(son[p][g]) dfs(son[p][g],l+1);
        return;
    }
    if(g==5)
    {
        FOR(i,0,3) if(son[p][i]) dfs(son[p][i],l+1);
        return;
    }
    dfs(p,l+1);
    FOR(i,0,3) if(son[p][i])
    {
        dfs(son[p][i],l+1);
        dfs(son[p][i],l);
    }
}

signed main()
{
    cin>>S;
    int n=read();
    len=S.length();
    FOR(i,1,n)
    {
        cin>>s[i];
        insert(s[i]);
    }
    dfs(1,0);
    write(n-ans);
    return 0;
}
